function showCmt(url, sources, ydv) {
    let {
        java,
        cache
    } = this;
    const currentTime = Date.now();
    const click = cache.getFromMemory(url);
    let isqread = false;
    try {
        java.qread();
        isqread = true;
    } catch (e) {}
    if (click < 1 && !isqread && !ydv) {
        cache.putMemory(url, click + 1);
        return;
    } else {
        if (isqread) {
            java.startBrowserDp(url, sources + '段评');
        } else if (ydv) {
            let paradata = new Date().toLocaleDateString();
            let htmlContent = cache.get(paradata);
            if (!htmlContent || String(htmlContent).indexOf("评论") == -1) {
                java.longToast(`\n${paradata} 初始化段评页面,请稍等~`);
                try {
                    htmlContent = java.ajax(url);
