    /* 版本对比指示器 */
    .version-indicator {
      position: absolute;
      left: 50%;
      top: 50%;
      transform: translate(-50%, -50%);
      z-index: 5;
      width: 32px;
      height: 32px;
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
      color: white;
    }

    .version-indicator.update-needed {
      background: var(--error-color);
      box-shadow: 0 2px 8px rgba(234, 84, 85, 0.4);
      animation: pulse-indicator 1.5s infinite;
    }

    .version-indicator.is-latest {
      background: var(--success-color);
      box-shadow: 0 2px 8px rgba(40, 199, 111, 0.4);
    }

    @keyframes pulse-indicator {
      0% { transform: translate(-50%, -50%) scale(1); }
      50% { transform: translate(-50%, -50%) scale(1.1); }
      100% { transform: translate(-50%, -50%) scale(1); }
    }

    /* 内容区 */
    .content-container {
      padding: 16px;
    }

    /* 状态提示 */
    .status-alert {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
      margin-bottom: 16px;
      overflow: hidden;
      border: 1px solid rgba(120, 130, 240, 0.1);
      padding: 12px 16px;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 10px;
      font-weight: 500;
      font-size: 14px;
      animation: slideIn 0.5s ease 0.3s backwards;
    }

    .status-alert i {
      font-size: 20px;
    }

    .status-alert.update-available {
      background: linear-gradient(135deg, #ffeaa7 0%, #fdcb6e 100%);
      color: #d63031;
      box-shadow: 0 4px 15px rgba(253, 203, 110, 0.4);
    }

    .status-alert.up-to-date {
      background: linear-gradient(135deg, #55efc4 0%, #00b894 100%);
      color: white;
      box-shadow: 0 4px 15px rgba(0, 184, 148, 0.4);
    }

    /* 更新容器 */
    .update-container {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
      margin-bottom: 16px;
      overflow: hidden;
      border: 1px solid rgba(120, 130, 240, 0.1);
      animation: slideIn 0.5s ease 0.4s backwards;
    }

    .update-header {
      background: var(--light-bg);
      padding: 12px 16px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
    }

    .update-header h2 {
      font-size: 1rem;
      font-weight: 600;
      color: var(--text-main);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .update-header h2 i {
      color: #4e6ef2;
    }

    .update-tag {
      background: rgba(78, 110, 242, 0.1);
      color: #4e6ef2;
      padding: 4px 8px;
      border-radius: 8px;
      font-size: 0.75rem;
      font-weight: 600;
    }

    .update-content {
      padding: 16px;
    }

    .update-date {
      font-weight: 600;
      color: #4e6ef2;
      margin-bottom: 12px;
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 8px 0;
      border-bottom: 1px dashed #e0e0e0;
    }

    .update-text {
      margin: 8px 0;
      position: relative;
      padding-left: 16px;
      line-height: 1.5;
      color: var(--text-main);
      font-size: 0.95rem;
      white-space: pre-wrap;
      word-break: break-word;
    }

    .update-text::before {
      content: '•';
      position: absolute;
      left: 0;
      font-weight: bold;
      color: #4e6ef2;
      font-size: 1.2rem;
      line-height: 1;
    }

    /* 历史日志 */
    .history-container {
      background: var(--card-bg);
      border-radius: 16px;
      box-shadow: var(--shadow);
      margin-bottom: 16px;
      border: 1px solid rgba(120, 130, 240, 0.1);
      animation: slideIn 0.5s ease 0.5s backwards;
    }

    .history-header {
      background: var(--light-bg);
      padding: 12px 16px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
      cursor: pointer;
      user-select: none;
    }

    .history-header:hover {
      opacity: 0.8;
    }

    .history-header h2 {
      font-size: 1rem;
      font-weight: 600;
      color: var(--text-main);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .history-header h2 i {
      color: #4e6ef2;
    }

    .toggle-history {
      background: none;
      border: none;
      color: var(--text-secondary);
      cursor: pointer;
      font-weight: 500;
      display: flex;
      align-items: center;
      gap: 4px;
      font-size: 0.85rem;
      transition: color 0.2s ease;
    }

    .toggle-history:hover {
      color: #4e6ef2;
    }

    .history-content {
      padding: 0 16px;
      max-height: 0;
      overflow: hidden;
      transition: max-height 0.4s ease, padding 0.4s ease;
    }

    .history-content.expanded {
      max-height: 60vh;
      overflow-y: auto;
      padding: 16px;
      scrollbar-width: thin;
      scrollbar-color: #4e6ef2 #f0f0f0;
    }

    .history-content.expanded::-webkit-scrollbar {
      width: 6px;
    }

    .history-content.expanded::-webkit-scrollbar-track {
      background: #f0f0f0;
      border-radius: 4px;
    }

    .history-content.expanded::-webkit-scrollbar-thumb {
      background: #4e6ef2;
      border-radius: 4px;
    }

    .history-content.expanded::-webkit-scrollbar-thumb:hover {
      background: #3a56d0;
    }

    .history-item {
      margin-bottom: 16px;
      padding-bottom: 16px;
      border-bottom: 1px dashed var(--border-color);
    }

    .history-item:last-child {
      border-bottom: none;
      margin-bottom: 0;
      padding-bottom: 0;
    }

    .history-date {
      font-weight: 600;
      color: var(--text-main);
      margin-bottom: 8px;
      display: flex;
      align-items: center;
      gap: 4px;
      font-size: 0.9rem;
      background: rgba(78, 110, 242, 0.05);
      padding: 6px 10px;
      border-radius: 6px;
    }

    .history-text {
      margin: 8px 0;
      padding-left: 16px;
      line-height: 1.4;
      color: var(--text-secondary);
      position: relative;
      font-size: 0.9rem;
      white-space: pre-wrap;
      word-break: break-word;
    }

    .history-text::before {
      content: '•';
      position: absolute;
      left: 0;
      color: #4e6ef2;
      font-weight: bold;
      font-size: 1.2rem;
      line-height: 1;
    }

    /* 按钮组 */
    .button-group {
      display: flex;
      flex-direction: column;
      gap: 10px;
      margin-bottom: 16px;
    }

    .button {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 10px;
      padding: 14px 28px;
      text-align: center;
      font-size: 1rem;
      border: none;
      border-radius: 12px;
      text-decoration: none;
      background: var(--primary-gradient);
      color: white;
      font-weight: 600;
      transition: all 0.3s ease;
      box-shadow: var(--shadow);
      position: relative;
      overflow: hidden;
      cursor: pointer;
    }

    .button i {
      font-size: 1rem;
    }

    .button::after {
      content: '';
      position: absolute;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: rgba(255, 255, 255, 0.1);
      transform: rotate(30deg);
      transition: all 0.6s ease;
      pointer-events: none;
    }

    .button:hover {
      transform: translateY(-3px);
      box-shadow: var(--shadow-hover);
    }

    .button:hover::after {
      transform: rotate(30deg) translate(20%, 20%);
    }

    .button:active {
      transform: scale(0.95);
    }

    /* 错误状态 */
    .error-state {
      text-align: center;
      padding: 40px 20px;
      color: var(--text-main);
    }

    .error-icon {
      font-size: 64px;
      margin-bottom: 20px;
      color: var(--error-color);
    }

    .error-text {
      font-size: 16px;
      line-height: 1.6;
      margin-bottom: 20px;
    }

    .retry-button {
      background: var(--primary-gradient);
      color: white;
      padding: 12px 30px;
      border-radius: 12px;
      border: none;
      font-weight: 600;
      cursor: pointer;
      transition: all 0.3s ease;
      font-size: 14px;
      box-shadow: var(--shadow);
    }

    .retry-button:hover {
      transform: translateY(-2px);
      box-shadow: var(--shadow-hover);
    }

    .retry-button:active {
      transform: scale(0.95);
    }

    /* 装饰元素 */
    .decoration {
      position: absolute;
      z-index: 0;
      pointer-events: none;
    }

    .decoration.circle {
      width: 120px;
      height: 120px;
      border-radius: 50%;
      background: rgba(107, 45, 216, 0.05);
      top: 10%;
      left: 10%;
    }

    .decoration.square {
      width: 80px;
      height: 80px;
      transform: rotate(45deg);
      background: rgba(78, 110, 242, 0.05);
      bottom: 10%;
      right: 10%;
    }

    /* 响应式 */
    @media (max-width: 768px) {
      body {
        padding: 12px;
      }

      .container {
        max-width: 100%;
        border-radius: 20px;
      }

      .header {
        padding: 20px 15px;
      }

      .header h1 {
        font-size: 1.3rem;
      }

      .header-icon {
        font-size: 40px;
      }

      .version-comparison {
        flex-direction: row;
        flex-wrap: nowrap;
        gap: 10px;
        padding: 12px;
        margin-top: 6px;
        overflow-x: auto;
      }

      .version-card {
        min-width: 45%;
        padding: 26px 12px 12px;
      }

      /* 移动端减弱呼吸动效 */
      .version-card.latest-version {
        animation: gradientAnimation 6s ease infinite;
      }

      .version-status {
        top: 5px;
        right: 5px;
        padding: 2px 5px;
        font-size: 0.6rem;
      }

      .version-number {
        font-size: 1.1rem;
      }

      .version-card.latest-version .version-number {
        font-size: 1.2rem;
      }

      .update-header h2, .history-header h2 {
        font-size: 0.9rem;
      }

      .button {
        padding: 12px 24px;
        font-size: 0.95rem;
      }

      .history-content.expanded {
        max-height: 50vh;
        -webkit-overflow-scrolling: touch;
      }
    }

    @media (max-width: 380px) {
      .header h1 {
        font-size: 1.2rem;
      }

      .version-number {
        font-size: 1rem;
      }

      .version-card.latest-version .version-number {
        font-size: 1.1rem;
      }

      .button {
        padding: 11px;
        font-size: 0.9rem;
      }
    }
  </style>
</head>
