@js:
// 示例数据（需替换为实际值）
var keyHex = "54524876596270476c4e466f4f644c6158724b5259677664477747666a6e4a6a";   // 32 位十六进制（16 字节）
var ivHex = "6b424b58514970465954444f48474c516c52556b6c504c744e5063424b537665";// 32 位十六进制（16 字节）
var http = baseUrl.split('/').filter(part => part !== "");
var cid = http[http.length - 1]
var page = 1
var picList = []

var OkHttpClient = Packages.okhttp3.OkHttpClient;
var Request = Packages.okhttp3.Request;
var client = new OkHttpClient();

var HttpUrl = Packages.okhttp3.HttpUrl;

function getList(page, cid) {
    var baseApi = HttpUrl.parse("https://www.0592cr.com/index.php/api/data/pic");
    var url = baseApi.newBuilder()
        .addQueryParameter("page", page)
        .addQueryParameter("cid", cid)
        .build();

    var headers = new Packages.okhttp3.Headers.Builder()
        .add("User-Agent", "Mozilla/5.0 (Linux; Android 6.0; Nexus 5 Build/MRA58N) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/143.0.0.0 Mobile Safari/537.36")
        .add("Accept", "text/javascript, application/javascript, application/ecmascript, application/x-ecmascript, */*; q=0.01")
        .add("Referer", baseUrl)
        .build();

    var request = new Request.Builder()
        .url(url)
        .headers(headers)
        .build();

    var response = client.newCall(request).execute();
    var responseBody = JSON.parse(response.body().string());
    // java.log(response);
    if (responseBody.code == 1) {
        return responseBody.data
    }
}

function decryptAesCbc(hexKey, hexIv, base64Data) {
    const key = CryptoJS.enc.Hex.parse(keyHex);
    const iv = CryptoJS.enc.Hex.parse(ivHex);

    const decrypted = CryptoJS.AES.decrypt(base64Data, key, {
        iv: iv, mode: CryptoJS.mode.CBC,    // 指定CBC模式
        padding: CryptoJS.pad.Pkcs7 // 指定PKCS7填充（默认即此，可省略）
    });

    const decryptedText = decrypted.toString(CryptoJS.enc.Utf8);
    return decryptedText;
}

(function getImgList() {
    while (true) {
        var ccc = getList(page, cid)
        var plainText = JSON.parse(decryptAesCbc(keyHex, ivHex, ccc));
        if (plainText.length == 0) {
            break
        } else {
            for (let n = 0; n < plainText.length; n++) {
                // java.log(plainText[n].img);
                picList.push(plainText[n].img)
            }
            page++
        }
    }
    return picList
}()).map(url => ' <img src = "' + url + '" > ').join("\n")

