@js:
var src = String(result);
var doc = org.jsoup.Jsoup.parse(src);

function decode(d) {
    var scripts = d.select('script');
    var s = '';
    for (var i = 0; i < scripts.size(); i++) {
        var data = scripts.get(i).data();
        var m = data.match(/qsbs\.bb\('([^']+)'\)/);
        if (m) {
            try {
                var bytes = Packages.java.util.Base64.getDecoder().decode(m[1]);
                s += String(new Packages.java.lang.String(bytes, 'UTF-8'));
            } catch(e) {}
        }
    }
    return s;
}

var content = decode(doc);

var m = baseUrl.match(/kuaishou\/(\d+)\/(\d+)(?:_\d+)?\.html/);
if (m) {
    var bid = m[1];
    var cid = m[2];
    for (var p = 1; p < 50; p++) {
        try {
            var url = 'https://www.huiysj.com/kuaishou/' + bid + '/' + cid + '_' + p + '.html';
            var html = String(java.ajax(url));
            if (!html) break;
            // FIX: Check page number to detect 301 redirect to page 1
            // Page p should be "第(p+1)页", if we get "第1页" it's a redirect
            var pMatch = html.match(/\uff08\u7b2c(\d+)\u9875\uff09/);
            if (!pMatch) break;
            if (parseInt(pMatch[1]) !== p + 1) break;
            var nextContent = decode(org.jsoup.Jsoup.parse(html));
            if (!nextContent || nextContent === '') break;
            content += nextContent;
        } catch(e) { break; }
    }
}
content;

ruleToc.chapterList:
@js:
var src = String(result);
var doc = org.jsoup.Jsoup.parse(src);
var bookId = baseUrl.match(/kuaishou\/(\d+)/)[1];
var list = new Packages.java.util.ArrayList();
var seen = {};

function addChap(name, url) {
    if (url && url.indexOf('kuaishou') >= 0 && !seen[url]) {
        seen[url] = 1;
        var map = new Packages.java.util.HashMap();
        map.put("name", name);
        map.put("url", url);
        list.add(map);
    }
}

var sections = doc.select('div.info_dv3');
for (var s = 0; s < sections.size(); s++) {
    var sec = sections.get(s);
    var title = sec.select('div.title').text();
    if (title.indexOf('\u7ae0\u8282\u5217\u8868') >= 0) {
        var links = sec.select('a[href*=/kuaishou/]');
        for (var i = 0; i < links.size(); i++) {
            var a = links.get(i);
            var nm = a.text();
            var hr = a.attr('abs:href');
            if (nm && hr && hr.indexOf('all_') < 0) {
                addChap(nm, hr);
            }
        }
    }
}

var moreLink = doc.select('a:containsOwn(\u67e5\u770b\u66f4\u591a)');
if (moreLink.size() > 0) {
    for (var p = 1; p < 30; p++) {
        try {
            var pageUrl = 'https://www.huiysj.com/kuaishou/' + bookId + '/all_' + p + '/index.html';
            var html = String(java.ajax(pageUrl));
            if (!html || html.indexOf('read_tz') < 0) break;
            var d2 = org.jsoup.Jsoup.parse(html);
            var items = d2.select('ul.yanqing_list li a');
            if (items.size() === 0) break;
            for (var k = 12; k < items.size(); k++) {
                var a2 = items.get(k);
                var nm2 = a2.text();
                var oc = a2.attr('onclick');
                var m = oc.match(/read_tz\((\d+)\)/);
                if (m) {
                    addChap(nm2, 'https://www.huiysj.com/kuaishou/' + bookId + '/' + m[1] + '.html');
                }
            }
        } catch(e) { break; }
    }
}

list;

