@js:
var url='https://www.huiysj.com/kuaishou/';
var bookId = baseUrl.match(/kuaishou\/(\d+)/)[1];
var list = new Packages.java.util.ArrayList();
firstPage();
otherPage();

function firstPage() {
    var doc = org.jsoup.Jsoup.parse(result.toString());
    var sections = doc.select('div.info_dv3');
    for (var s = 0; s < sections.size(); s++) {
        var sec = sections.get(s);
        var title = sec.select('div.title').text();
        if (title.indexOf('\u7ae0\u8282\u5217\u8868') >= 0) {
            var links = sec.select('a[href*=/kuaishou/]');
            for (var i = 0; i < links.size(); i++) {
                var a = links.get(i);
                var name = a.text();
                var hr = a.attr('abs:href');
                if (name && hr && hr.indexOf('all_') < 0) {
                    addChap(name, hr);
                }
            }
        }
    }
}

function otherPage() {
    for (var p = 1; p < 100; p++) {
        var pageUrl = url + bookId + '/all_' + p + '/index.html';
        var html = String(java.ajax(pageUrl));
        if (!html || html.indexOf('章节列表（第1页）') > 0) {
            break;
        }
        var d2 = org.jsoup.Jsoup.parse(html);
        var str = d2.select('style').toString();
        var nthChildCount = (str.match(/ul\.yanqing_list>li:nth-child\(/g) || []).length;
        var nthLastChildCount = (str.match(/ul\.yanqing_list>li:nth-last-child\(/g) || []).length;
        var items = d2.select('ul.yanqing_list li a');
        if (items.size() === 0) break;
        for (var k = nthChildCount; k < items.size() - nthLastChildCount; k++) {
            var a2 = items.get(k);
            var name = a2.text();
            var oc = a2.attr('onclick');
            var m = oc.match(/read_tz\((\d+)\)/);
            if (m) {
                addChap(name, url + bookId + '/' + m[1] + '.html');
            }
        }
    }
}

function addChap(name, url) {
    if (url && url.indexOf('kuaishou') >= 0) {
        var map = new Packages.java.util.HashMap();
        map.put("name", name);
        map.put("url", url);
        list.add(map);
    }
}

list;

