		    	})
    });
    urlData.data = data;
    source.setVariable(JSON.stringify(urlData));    
}

function getUrl(){
    const {source} = this;
    	let s = String(source.getVariable());
    if(!s){
    	     this.putUrl();
        	 s = String(source.getVariable());
    	}
    let urlData = JSON.parse(s);
    let index = urlData.index;
    let data = urlData.data;
	return data[index].t.replace(/\/$/,'');	
}

