jsLib:
var CKU = "https://api.lightnovel.fun";

function rd(cookie) {
    try {
        var v = cookie.getKey(CKU, "lkcfg");
        if (v) return JSON.parse(decodeURIComponent(v));
    } catch (e) {}
    return {};
}

function wr(cookie, c) {
    try {
        cookie.setCookie(CKU, "lkcfg=" + encodeURIComponent(JSON.stringify(c)));
    } catch (e) {}
}

function gv(cookie) {
    var c = rd(cookie);
    return (c.key && ("" + c.key).indexOf(":") > 0) ? c.key : "";
}

function getType(cookie) {
    var c = rd(cookie);
    return (c.type != null && c.type !== "") ? parseInt(c.type) : 2;
}

function setType(java, cookie, t) {
    var c = rd(cookie);
    c.type = t;
    wr(cookie, c);
    var n = {
        2: "轻小说",
        5: "漫画",
        4: "动画",
        3: "资讯",
        0: "综合"
    };
    java.toast("已切到「" + (n[t] || t) + "」,直接搜索即可");
}

function getZh(cookie) {
    var c = rd(cookie);
    return c.zh || "";
}

function setZh(java, cookie) {
    var c = rd(cookie);
    c.zh = (c.zh == "s") ? "" : "s";
    wr(cookie, c);
    java.toast(c.zh == "s" ? "🈶 繁→简 已开启" : "🈶 已关闭,显示原文(繁体)");
}

function getPure(cookie) {
    var c = rd(cookie);
    return c.pure !== false;
}

function setPure(java, cookie) {
    var c = rd(cookie);
    var cur = (c.pure !== false);
    c.pure = !cur;
    wr(cookie, c);
    java.toast(!cur ? "🔍 精准搜索:开 (只搜可读,过滤epub/下载)" : "🔍 精准搜索:关 (搜全部)");
}

function clearLogin(java, cookie) {
    var c = rd(cookie);
    delete c.key;
    wr(cookie, c);
    java.toast("🗑️ 已清除登录");
}

function showStatus(java, cookie) {
    var k = gv(cookie);
    var n = {
        2: "轻小说",
        5: "漫画",
        4: "动画",
        3: "资讯",
        0: "综合"
    };
    if (!k) {
        java.toast("⚪ 未登录 - 请填账号密码点登录");
        return;
    }
    try {
        var payload = JSON.stringify({
            platform: "android",
            client: "app",
            sign: "",
            ver_name: "0.11.53",
            ver_code: 193,
            gz: 0,
            d: {
                security_key: k
            }
        });
        var r = JSON.parse(String(java.post(CKU + "/api/search/get-search-tags", payload, {
            "Content-Type": "application/json"
        }).body()));
        if (r.code == 0) {
            java.toast("✅ 已登录 uid:" + k.split(":")[1] + "  分类:" + (n[getType(cookie)] || ""));
        } else {
            java.toast("⚠️ 登录失效,请重登 (code:" + r.code + ")");
        }
    } catch (e) {
        java.toast("检查失败:" + e);
    }
}

function reqUrl(cookie, path, d) {
    d = d || {};
    d.security_key = gv(cookie);
    var payload = JSON.stringify({
        platform: "android",
        client: "app",
        sign: "",
        ver_name: "0.11.53",
        ver_code: 193,
        gz: 0,
        d: d
    });
    var opt = JSON.stringify({
        method: "POST",
        body: payload,
        headers: {
            "Content-Type": "application/json"
        }
    });
    return CKU + path + "," + opt;
}

function bb(s) {
    s = "" + (s || "");
    s = s.replace(/\[img[^\]]*\]([^\[]+)\[\/img\]/gi, '\n<img src="$1">\n');
    s = s.replace(/<iframe[^>]*src=["\x27]?([^"\x27 >]+)[^>]*>[\s\S]*?<\/iframe>/gi, "\n[视频] $1\n");
    s = s.replace(/\[\/?[a-zA-Z][^\]]*\]/g, "");
    return s.replace(/\r/g, "").replace(/\n{3,}/g, "\n\n");
}

function doLogin(java, source, cookie) {
    var m = source.getLoginInfoMap();
    var u = m.get("账号"),
        p = m.get("密码");
    if (!u || !p) {
        throw new Error("请先填账号和密码");
    }
    var payload = JSON.stringify({
        platform: "android",
        client: "app",
        sign: "",
        ver_name: "0.11.53",
        ver_code: 193,
        gz: 0,
        d: {
            username: u,
            password: p
        }
    });
    var r = JSON.parse(String(java.post(CKU + "/api/user/login", payload, {
        "Content-Type": "application/json"
    }).body()));
    if (r.code == 0 && r.data && r.data.security_key) {
        var c = rd(cookie);
        c.key = r.data.security_key;
        wr(cookie, c);
        java.toast("✅ 登录成功 uid:" + r.data.uid);
        return true;
    }
    throw new Error(r.code == 1001 ? "账号或密码错误" : ("登录失败 code:" + r.code));
}

function Login(java, source, cookie) {
    doLogin(java, source, cookie);
}

function login() {
    var j, s, ck;
    try {
        j = java;
    } catch (e) {}
    try {
        s = source;
    } catch (e) {}
    try {
        ck = cookie;
    } catch (e) {}
    if ((!j || typeof j.post !== 'function') && this) {
        j = this.java;
    }
    if ((!s || !s.getLoginInfoMap) && this) {
        s = this.source;
    }
    if ((!ck || !ck.getKey) && this) {
        ck = this.cookie;
    }
    if (j && typeof j.post === 'function' && s && s.getLoginInfoMap && ck && ck.getKey) {
        return doLogin(j, s, ck);
    }
    throw new Error('请用下方【🔑登录账号】按钮登录');
}

