<script>
var _replyData=null,_chapterUrl="",_rawParams="",_scrollAfterLoad=false;
function updateView(params){
    window.run("getChapterComments("+params+")").then(function(result){
        document.getElementById("loading").classList.add("hidden");
        if(result&&result!==""){
            var tpl=document.createElement("template");
            tpl.innerHTML=result;
            document.getElementById("comment-list").appendChild(tpl.content);
        }else{
            document.getElementById("no_data").classList.remove("hidden");
        }
        if(_scrollAfterLoad){_scrollAfterLoad=false;var sa=document.getElementById("scroll-area");sa.scrollTop=sa.scrollHeight;}
    }).catch(function(){
        document.getElementById("loading").classList.add("hidden");
        document.getElementById("no_data").classList.remove("hidden");
    });
}
function showReplyForm(btn){
    _replyData=btn.getAttribute("data-comment");
    var hint=document.getElementById("reply-hint");
    hint.textContent="回覆 "+btn.getAttribute("data-author");
    hint.style.display="block";
    document.getElementById("btn-cancel-reply").style.display="";
    document.getElementById("comment-textarea").focus();
}
function cancelReply(){
    _replyData=null;
    document.getElementById("reply-hint").style.display="none";
    document.getElementById("btn-cancel-reply").style.display="none";
}
function refreshComments(){document.getElementById("comment-list").innerHTML="";document.getElementById("no_data").classList.add("hidden");document.getElementById("loading").classList.remove("hidden");_scrollAfterLoad=true;updateView(_rawParams);}
function submitComment(){
    var content=document.getElementById("comment-textarea").value.trim();
    if(!content){document.getElementById("comment-textarea").focus();return;}
    content=content.split(String.fromCharCode(10)).join("<br>");
    var btn=document.getElementById("btn-submit");
    var st=document.getElementById("post-status");
    btn.disabled=true;st.textContent="送出中...";
    window.run("postForumReply("+JSON.stringify(_chapterUrl)+","+JSON.stringify(content)+","+JSON.stringify(_replyData||"")+")").then(function(res){
        btn.disabled=false;
        try{
            var r=JSON.parse(res);
            if(r.status===200){
                document.getElementById("comment-textarea").value="";
                cancelReply();
                st.textContent="已送出！";
                setTimeout(function(){st.textContent="";refreshComments();},1500);
            }else{st.textContent=r.msg||"送出失敗";}
        }catch(e){st.textContent="送出失敗";}
    }).catch(function(){btn.disabled=false;st.textContent="網路錯誤";});
}
var el=document.getElementById("params");
if(el){
    var raw=el.innerText.trim();
    _chapterUrl=raw.charAt(0)==="'"?raw.slice(1,-1):raw;
    _rawParams=raw;
    updateView(raw);
}
</script></body>
</html>`;

function showChapterComments() {
    var java = this.java,
        chapter = this.chapter,
        cookie = this.cookie;
    var aid = (String(chapter.url).match(/aid\W+(\d+)/) || [])[1] || "";
    var key = "";
    try {
        if (cookie && cookie.getKey) {
            var v = cookie.getKey("https://api.lightnovel.fun", "lkcfg");
            if (v) {
                var cc = JSON.parse(decodeURIComponent(v));
                if (cc.key) key = cc.key;
            }
        }
    } catch (e) {}
    if (!key) {
        try {
            key = "" + (java.get("lk_key") || "");
        } catch (e) {}
    }
    var paramsHtml = '<div class="hidden" id="params">\'' + aid + '@@' + key + '\'</div>';
    java.showBrowser("", reviewHtmlTemplate.replace("$2", paramsHtml), "window.run=run", '{"heightPercentage":0.8,"expandedCornersRadius":20,"hideFriction":0.9}');
}

function escapeHtml(str) {
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

function fixRelativeUrls(html, origin) {
    if (html == null) return '';
    html = String(html);
    if (!html || !origin) return html;
    return html.replace(/\bsrc="([^"]+)"/g, function(m, url) {
        if (/^https?:\/\//i.test(url) || /^data:/i.test(url)) return m;
        if (url.charAt(0) === '/') return 'src="' + origin + url + '"';
        return 'src="' + origin + '/' + url + '"';
    });
}

function unescapeLkTags(s) {
    s = s.replace(/&lt;br\s*\/?&gt;/gi, "<br>");
    s = s.replace(/&lt;img\s+src=&quot;([^&]+)&quot;[\s\S]*?&gt;/gi, '<img src="$1" style="height:1.4em;vertical-align:middle">');
    return s;
}

function getChapterComments(param) {
    var java = this.java;
    var parts = ("" + param).split("@@");
    var aid = parts[0] || "";
    var key = parts[1] || "";
    if (!key) {
        try {
            key = "" + (java.get("lk_key") || "");
        } catch (e) {}
    }
    var body = JSON.stringify({
        platform: "android",
        client: "app",
        sign: "",
        ver_name: "0.11.53",
        ver_code: 193,
        gz: 0,
        d: {
            aid: parseInt(aid),
            page: 1,
            page_size: 20,
            security_key: key
        }
    });
    var resp = String(java.post("https://api.lightnovel.fun/api/discuss/get-topic", body, {
        "Content-Type": "application/json"
    }).body());
    var r = JSON.parse(resp);
    var lst = (r.data && r.data.list) || [];
    if (!lst.length) return "";
    var result = [];
    for (var i = 0; i < lst.length; i++) {
        var c = lst[i];
        var u = c.user_info || {};
        var item = '<li class="comment-item">';
        item += '<div class="comment-header"><span class="comment-author">' + escapeHtml(u.nickname || "匿名") + '</span><span class="comment-meta">' + escapeHtml(c.time || "") + '</span></div>';
        item += '<div class="comment-text">' + unescapeLkTags(escapeHtml(c.content || "")) + '</div>';
        var rl = c.reply_list || [];
        for (var k = 0; k < rl.length; k++) {
            var rc = rl[k];
            var ru = rc.user_info || {};
            item += '<div class="comment-quote"><b>' + escapeHtml(ru.nickname || "") + '</b>: ' + unescapeLkTags(escapeHtml(rc.content || "")) + '</div>';
        }
        item += '</li>';
        result.push(item);
    }
    return result.join("");
}

function postForumReply(chapterUrl, content, replyData) {
    var tokenBody;
    try {
        tokenBody = this.java.post(
            chapterUrl,
            'plxf=getAuthToken', {
                'Content-Type': 'application/x-www-form-urlencoded'
            }
        ).body();
    } catch (e) {
        return JSON.stringify({
            status: 500,
            msg: '無法連接伺服器'
        });
    }
    var tokenMatch = /<JinJing>(.*?)<\/JinJing>/.exec(tokenBody);
    if (!tokenMatch) {
        return JSON.stringify({
            status: 500,
            msg: '獲取令牌失敗'
        });
    }
    var token = tokenMatch[1];
    var originMatch = /^(https?:\/\/[^\/]+)/.exec(chapterUrl);
    var origin = originMatch ? originMatch[1] : source.bookSourceUrl;
    var forumMatch = /\/(\d+)\.html/.exec(chapterUrl);
    if (!forumMatch) {
        return JSON.stringify({
            status: 500,
            msg: '無法解析章節ID'
        });
    }
    var forumId = forumMatch[1];
    var postBody = 'data=forum&forum_id=' + encodeURIComponent(forumId) + '&content=' + encodeURIComponent(content);
    if (replyData) {
        postBody += '&reply=' + encodeURIComponent(replyData);
    }
    var responseBody;
    try {
        responseBody = this.java.post(
            origin + '/inc/forum_reply.php',
            postBody, {
                'Content-Type': 'application/x-www-form-urlencoded',
                'Authorization': token
            }
        ).body();
    } catch (e) {
        return JSON.stringify({
            status: 500,
            msg: '網路錯誤'
        });
    }
    return responseBody;
}

