// 中文
function randomChinese() {
    const min = 0x4e00;
    const max = 0x9fff;
    const code = Math.floor(Math.random() * (max - min + 1)) + min;
    return String.fromCharCode(code);
}

// 英文
function randomEnglish() {
    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    return chars[Math.floor(Math.random() * chars.length)];
}

// 随机用户名（混合）
function generateRandomUsername() {
    const minLen = 1;
    const maxLen = 10;
    const len = Math.floor(Math.random() * (maxLen - minLen + 1)) + minLen;

    let username = '';
    for (let i = 0; i < len; i++) {
        if (Math.random() > 0.5) {
            username += randomChinese();
        } else {
            username += randomEnglish();
        }
    }

    return username;
}

// 随机邮箱
function generateRandomEmail() {
    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    const userLen = Math.floor(Math.random() * 18) + 3;
    let username = '';
    for (let i = 0; i < userLen; i++) {
        username += chars[Math.floor(Math.random() * chars.length)];
    }

    const domains = ['gmail.com', '163.com', 'qq.com', 'hotmail.com', 'yahoo.com',
        'sina.com', '126.com', 'outlook.com', 'test.com', 'example.com', 'sh.sh'
    ];
    const domain = domains[Math.floor(Math.random() * domains.length)];

    return `${username}@${domain}`;
}

// 随机密码
function generateRandomPassword() {
    const minLen = 6;
    const maxLen = 20;
    const len = Math.floor(Math.random() * (maxLen - minLen + 1)) + minLen;

    let password = '';
    for (let i = 0; i < len; i++) {
        password += Math.floor(Math.random() * 10);
    }

    return password;
}

function generateRandomInfo() {
    return {
        username: generateRandomUsername(),
        email: generateRandomEmail(),
        password: generateRandomPassword()
    };
}

