(() => {
    const isImage = (result[0] === 0xFF && result[1] === 0xD8) ||
        (result[0] === 0x89 && result[1] === 0x50) ||
        (result[0] === 0x47 && result[1] === 0x49) ||
        (result[0] === 0x52 && result[1] === 0x49);
    if (isImage) return result;
    var iv = result.slice(0, 16);
    var ciphertext = result.slice(16);
    var key = java.strToBytes('0B6666A0-BB59-1381-B746-a0E4C9AC');
    var cipher = java.createSymmetricCrypto("AES/CBC/PKCS5Padding", key, iv);
    return cipher.decrypt(ciphertext);
})();

