function processHtml(str){
    const {java} = this;
    let doc = org.jsoup.Jsoup.parse(str);
    let link,js;
    if (!doc) {
        return str;
    }
     var atag = doc.select("a");
     for (var i = 0; i < atag.size(); i++) {
         var e = atag.get(i);
         let link = e.attr("href");
         let text = e.text()?e.text("网页链接"):e.text();
         let img =this.getClickImg("link",link)+text;
         img = img.replace(/{.*}/,function (match){
             return match.replace(/"/g,'&quot;')
         });

        e.html(img);

        }

        var videocard = doc.select(".video-card,.article-card");
        for (var i = 0; i < videocard.size(); i++) {
            var e = videocard.get(i);
            let aa = "";
            let type =  /video/.test(e.attr("class"))?"video":"article";
            let link = e.attr("aid");
            if(/,/.test(link)){
                let linkl = link.split(",");
                linkl.forEach(x=>{
                    aa+=this.getClickImg(type,x)+x+"<br>";
                });
                e.before(aa.replace(/"/g,'&quot;'))
            }else{
             let img = this.getClickImg(type,link,e.attr("src"),1);
             img = img.match(/src="(.*)"/)[1];
             e.attr("src",img);
             }

         }
         let result = String(doc.toString()).replace(/<\/img>/g,'')
         return result
}

function processDelta(data) {
	const {java} = this
    try {
        if (!data || !Array.isArray(data)) {
            return "无效的数据格式";
        }
        var html = "";
        var prevText = "";
        var js;
        for (var i = 0; i < data.length; i++) {
            var item = data[i];
            var currenttext = "";
            var insert = item.insert;

            if (insert) {
                if (typeof insert === "string") {

                    var attr = item.attributes ?? {};                   
                        if (attr.link) {
                            html += `${this.getClickImg("link",attr.link)}${insert}`
                        }else{
                        html += insert
                    }
                }else if(typeof insert == "object"){                 
                    let image = insert["native-image"];
                    if(image){                			
                        html += `<img src="${image.url}">\n`
                	}

                    let cut_off = insert["cut-off"];
                    if(cut_off){
