function modifyDanmaku(xmlStr, fontSize) {
    if (!xmlStr) return xmlStr;

    var size = Math.max(1, parseInt(fontSize) || 25);
    var count = 0;

    // 使用一个正则表达式同时处理两个功能
    var result = xmlStr.replace(
        /(<d p="[^"]+">[^<]*<\/d>)/g,
        function(match) {
            if (count >= 1500) {
                return '';
            }
            count++;

            // 修改字体大小
            return match.replace(
                /<d p="([^,]+),([^,]+),([^,]+),([^,]+),([^,]+),([^,]+),([^,]+),([^,]+),([^,]+)">/,
                `<d p="$1,$2,${size},$4,$5,$6,$7,$8,$9">`
            );
        }
    );

    return result;
}


function generateMPD(Data) {

    let video = Data.video;
    let videoData;


    for(let i=1;i<video.length;i++){
    	if(video[i].codecid === 7){

    		videoData = video[i];
    		break
		}
	}

    let audioData = Data.audio[1];
    let duration = Data.duration;
    const videoBaseUrl = videoData.baseUrl;
    const audioBaseUrl = audioData.baseUrl;

    const videoSegmentBase = videoData.segment_base || videoData.SegmentBase;
    const audioSegmentBase = audioData.segment_base || audioData.SegmentBase;

    const videoInitRange = videoSegmentBase.initialization || videoSegmentBase.Initialization;
    const videoIndexRange = videoSegmentBase.index_range || videoSegmentBase.indexRange;

    const audioInitRange = audioSegmentBase.initialization || audioSegmentBase.Initialization;
    const audioIndexRange = audioSegmentBase.index_range || videoSegmentBase.indexRange;

    // 将duration格式化为ISO 8601持续时间格式
    // duration应为秒数，格式化为PTxS格式
    const durationStr = "PT" + duration + "S";

    const mpdContent = `<MPD xmlns="urn:mpeg:dash:schema:mpd:2011" profiles="urn:mpeg:dash:profile:full:2011" type="static" mediaPresentationDuration="${durationStr}" minBufferTime="PT1.5S">
    <Period id="0" start="PT0.0S">
        <AdaptationSet id="0" contentType="video" width="${videoData.width}" height="${videoData.height}" frameRate="${videoData.frameRate || videoData.frame_rate}" par="${videoData.sar}" segmentAlignment="true">
            <Representation id="${videoData.id}" bandwidth="${videoData.bandwidth}" codecs="${videoData.codecs}" mimeType="${videoData.mimeType || videoData.mime_type}">
                <BaseURL>${videoBaseUrl.replace(/&/g,'&amp;')}</BaseURL>
                <SegmentBase indexRange="${videoIndexRange}">
                    <Initialization range="${videoInitRange}"/>
                </SegmentBase>
            </Representation>
        </AdaptationSet>
        <AdaptationSet id="1" contentType="audio" segmentAlignment="true">
            <Representation id="${audioData.id}" bandwidth="${audioData.bandwidth}" codecs="${audioData.codecs}" mimeType="${audioData.mimeType || audioData.mime_type}">
                <BaseURL>${audioBaseUrl.replace(/&/g,'&amp;')}</BaseURL>
                <SegmentBase indexRange="${audioIndexRange}">
                    <Initialization range="${audioInitRange}"/>
                </SegmentBase>
            </Representation>
        </AdaptationSet>
    </Period>
</MPD>`;

    return mpdContent;
}

function formatTimeDynamic(totalSeconds) {
  const hours = Math.floor(totalSeconds / 3600);
  const remainingSeconds = totalSeconds % 3600;
  const minutes = Math.floor(remainingSeconds / 60);
  const seconds = remainingSeconds % 60;

  const parts = [];

  if (hours > 0) {
    parts.push(hours.toString().padStart(2, '0'));
  }

  // 如果有小时，分钟必须是2位
  if (hours > 0) {
    parts.push(minutes.toString().padStart(2, '0'));
  } else {
    parts.push(minutes.toString()); // 不足1小时，分钟不需要补0
  }

  parts.push(seconds.toString().padStart(2, '0'));

  return parts.join(':');
}

function formatCount(count) {
  if (count < 10000) return count.toString();  
  const inWan = (count / 10000).toFixed(2);
  return inWan.endsWith('.00') 
    ? `${inWan.split('.')[0]}万` 
    : `${inWan}万`;
}

 function getWbiEnc(queryJson) {
     const {java} = this;
    const mixinKeyEncTab = [
        46, 47, 18, 2, 53, 8, 23, 32, 15, 50, 10, 31, 58, 3, 45, 35, 27, 43, 5, 49,
        33, 9, 42, 19, 29, 28, 14, 39, 12, 38, 41, 13, 37, 48, 7, 16, 24, 55, 40,
        61, 26, 17, 0, 1, 60, 51, 30, 4, 22, 25, 54, 21, 56, 59, 6, 63, 57, 62, 11,
        36, 20, 34, 44, 52
    ];

    // 对 imgKey 和 subKey 进行字符顺序打乱编码
    function getMixinKey(orig) {
        let temp = '';
        mixinKeyEncTab.forEach((n) => {
            temp += orig[n]
        });
        return temp.slice(0, 32);
    }

    // 为请求参数进行 wbi 签名
    function encWbi(params, img_key, sub_key) {
        const mixin_key = getMixinKey(img_key + sub_key),
            curr_time = Math.round(Date.now() / 1000),
            chr_filter = /[!'\(\)*]/g
        let query = [];
        params = Object.assign(params, { wts: curr_time });    // 添加 wts 字段
        // 按照 key 重排参数
        Object.keys(params).sort().forEach((key) => {
            query.push(
                encodeURIComponent(key) +
                '=' +
                // 过滤 value 中的 "!'()*" 字符
                encodeURIComponent(('' + params[key]).replace(chr_filter, ''))
            )
        })
        query = query.join('&');
        const wbi_sign =String(java.md5Encode(query + mixin_key)); // 计算 w_rid
        return query + '&w_rid=' + wbi_sign;
    }

    // 获取最新的 img_key 和 sub_key
    function getWbiKeys() {
        const json_content = JSON.parse(java.ajax('https://api.bilibili.com/x/web-interface/nav')).data;
        let img_url = json_content.wbi_img.img_url;
        let sub_url = json_content.wbi_img.sub_url;
        return {
            img_key: img_url.substring(img_url.lastIndexOf('/') + 1, img_url.length).split('.')[0],
            sub_key: sub_url.substring(sub_url.lastIndexOf('/') + 1, sub_url.length).split('.')[0]
        }
    }

    const wbi_keys = getWbiKeys();

    const query = encWbi(
        queryJson,
        wbi_keys.img_key,
        wbi_keys.sub_key
    );
    return query;
}

