function toLogin(type) {
    let url = "https://www.lofter.com/lpt/login.do?product=lofter-android-8.3.20,";
    let phone = result ? result.get("账号") : "";
    let pwd = result ? result.get("密码[或短信验证码]") : "";
    let body = "";
    switch (type) {
        case 'phone':
            body = `deviceType=0&clientType=0&passport=${java.digestHex(pwd,"SHA-256")}&phone=${phone}&sourceType=0&type=0`
            break;

        case 'code':
            body = `deviceType=0&clientType=0&phone=${phone}&captcha=${pwd}&sourceType=0&type=1`
            break;

        case 'id':
            url = "https://www.lofter.com/lpt/account/login.do?product=lofter-android-8.3.20,";
            body = `password=${java.digestHex(pwd,"SHA-256")}&blogName=${phone}`;
            break;
    }

    let post = JSON.stringify({
        "method": "POST",
        "body": String(body)
    });
    //	java.log(post)
    let headers = {}
    let d = JSON.parse(java.ajax(url + post));
    java.toast(d.desc);

    if (d.result == 0) {
        headers["lofter-phone-login-auth"] = d.token;
        source.putLoginHeader(JSON.stringify(headers));
    } else if (type == "id" && d.status == 200) {

        headers["authorization"] = "ThirdParty " + d.token;
        source.putLoginHeader(JSON.stringify(headers));

    }
}

