  color: var(--color-primary);
}

.toast-content {
  flex: 1;
  font-size: 14px;
  color: var(--text-primary);
  font-weight: 500;
}



@keyframes spin {
  to { transform: rotate(360deg); }
}

/* 保存按钮加载状态 */
