    <textarea id="customStylesValue" style="display: none;">{}</textarea>
  </div>

  <!-- Toast提示容器 -->
  <div id="toastContainer" class="toast-container"></div>
</div>

<script>
// SVG模板数据
const SVG_TEMPLATES = ${JSON.stringify(svgs)};
const STYLE_NAMES = ['起点样式', '番茄样式', '精致样式', '对话样式', '方框样式', '圆圈样式'];

// Toast提示函数
function showToast(message, type = 'info', duration = 2500) {
  const container = document.getElementById('toastContainer');
  const toast = document.createElement('div');
  toast.className = 'toast';

  const icons = {
    success: '<i class="fas fa-check"></i>',
    error: '<i class="fas fa-times"></i>',
    warning: '<i class="fas fa-exclamation-triangle"></i>',
    info: '<i class="fas fa-info-circle"></i>',
    loading: '<span class="loading-spinner"></span>'
  };

  toast.innerHTML = \`
    <div class="toast-icon \${type}">\${icons[type] || icons.info}</div>
    <div class="toast-content">\${message}</div>
  \`;

  container.appendChild(toast);

  setTimeout(() => {
    toast.classList.add('fade-out');
    setTimeout(() => {
      container.removeChild(toast);
    }, 300);
  }, duration);
}

function showAlert(message) {
  showToast(message, 'info');
}

function showSuccess(message) {
  showToast(message, 'success');
}

function showError(message) {
  showToast(message, 'error');
}

function showConfirm(message, onConfirm) {
  const confirm = window.confirm(message);
  if (confirm && onConfirm) {
    onConfirm();
  }
}

// 当前设置
let settings = {
  '段评开关': '${(data && data.段评开关) || 'true'}',
  '气泡增大': '${(data && data.气泡增大) || 'false'}',
  '段评样式': '${(data && data.段评样式) || '0'}',
  '段评边框颜色': '${(data && data.段评边框颜色) || '#A7A7A7'}',
  '段评字体颜色': '${(data && data.段评字体颜色) || '#A7A7A7'}',
  '段评填充颜色': '${(data && data.段评填充颜色) || 'transparent'}'
};

// 自定义样式对象 {"自定义样式1": "<svg>...</svg>", ...}
let customStyles = {};
function initCustomStyles() {
  customStyles = {};
}
function fetchCustomStyles() {
  const baseUrl = document.getElementById('baseUrlValue').textContent;
  const qttoken = document.getElementById('qttokenValue').textContent;
  if (!baseUrl || !qttoken) {
    return;
  }
  const url = baseUrl + '/user_settings?set_type=legado_para&qttoken=' + encodeURIComponent(qttoken);
  fetch(url, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json'
    }
  }).then(response => response.json())
    .then(data => {
      if (data && data.data && data.data['自定义段评样式']) {
        customStyles = data.data['自定义段评样式'];
      }
      updateHiddenSettings();
      renderCustomStyles();
      updateStyleSelector();
      renderPreview();
    })
    .catch(err => {
      console.error('获取自定义段评样式失败:', err);
    });
}
function saveCustomStyles() {
  const saveBtn = document.getElementById('saveCustomStyleBtn');
  const baseUrl = document.getElementById('baseUrlValue').textContent;
  const qttoken = document.getElementById('qttokenValue').textContent;
  if (!baseUrl || !qttoken) {
    showAlert('无法获取配置信息');
    return;
  }    
  const url = baseUrl + '/user_settings?qttoken=' + encodeURIComponent(qttoken);
  const body = {
    legado_para: {
        '段评开关': settings['段评开关'],
        '气泡增大': settings['气泡增大'],
        '段评样式': settings['段评样式'],
        '段评边框颜色': settings['段评边框颜色'],
        '段评字体颜色': settings['段评字体颜色'],
        '段评填充颜色': settings['段评填充颜色'],
        '自定义段评样式': customStyles
    }
  };
  fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(body)
  }).then(response => response.json())
    .then(data => {
      saveBtn.classList.remove('loading');
      if (data && data.code === 0) {
        showSuccess('保存成功');
      } else {
        showError('保存失败: ' + (data && data.message || '未知错误'));
      }
    })
    .catch(err => {
      console.error('保存自定义段评样式失败:', err);
      showError('保存失败');
    });
}

// HTML转义函数
function htmlEscape(str) {
  if (!str) return str;
  return str.replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;');
}

// HTML反转义函数
function htmlUnescape(str) {
  if (!str) return str;
  return str.replace(/&amp;/g, '&')
            .replace(/&lt;/g, '<')
            .replace(/&gt;/g, '>')
            .replace(/&quot;/g, '"')
            .replace(/&#039;/g, "'");
}

// 更新隐藏设置
function updateHiddenSettings() {
  document.getElementById('duanpingSwitchValue').textContent = settings['段评开关'];
  document.getElementById('bubbleLargeSwitchValue').textContent = settings['气泡增大'];
  document.getElementById('duanpingStyleValue').textContent = settings['段评样式'];
  document.getElementById('borderColorValue').textContent = settings['段评边框颜色'];
  document.getElementById('fontColorValue').textContent = settings['段评字体颜色'];
  document.getElementById('fillColorValue').textContent = settings['段评填充颜色'];
  document.getElementById('customStylesValue').textContent = htmlEscape(JSON.stringify(customStyles));
}

// 获取下一个自定义样式名称
function getNextStyleName() {
  let count = 1;
  while (customStyles['自定义样式' + count]) {
    count++;
  }
  return '自定义样式' + count;
}

// 添加自定义样式
function addCustomStyle() {
  const name = getNextStyleName();
  customStyles[name] = '<svg xmlns="http://www.w3.org/2000/svg" width="100" height="90" viewBox="0 0 25 17" fill="none"><rect x="0.5" y="0.5" width="24" height="16" rx="2.5" ry="2.5" stroke="$color" style="stroke-opacity: 0.5; fill: $tccolor; fill-opacity: 0.5;"/><text x="12.5" y="12" text-anchor="middle" font-size="10" fill="$fontcolor" font-family="Arial, sans-serif">$displayText</text></svg>';
  renderCustomStyles();
  updateHiddenSettings();
  updateStyleSelector();
  renderPreview();
}

// 获取选中的样式名称
function getSelectedStyleName() {
  const styleValue = settings['段评样式'];
  // 如果是数字，返回默认样式名称
  if (!isNaN(styleValue)) {
    return STYLE_NAMES[parseInt(styleValue)] || styleValue;
  }
  // 如果是自定义样式，返回自定义名称
  return styleValue;
}

// 删除自定义样式
function deleteCustomStyle(name) {
  showConfirm('确定删除 "' + name + '" 吗？', function() {
    delete customStyles[name];
    if (settings['段评样式'] === name) {
      settings['段评样式'] = '0';
    }
    renderCustomStyles();
    updateHiddenSettings();
    updateStyleSelector();
    renderPreview();
  });
}

// 更新自定义样式
function updateCustomStyle(name, value) {
  customStyles[name] = value;
  updateHiddenSettings();
  renderPreview();
}

// 重命名自定义样式
function renameCustomStyle(oldName, newName) {
  if (!newName || newName.trim() == '') return;
  if (customStyles[newName] && newName != oldName) {
    showAlert('名称已存在');
    return;
  }
  customStyles[newName] = customStyles[oldName];
  delete customStyles[oldName];
  // 如果当前选中的是旧名称，更新为新名称
  if (settings['段评样式'] === oldName) {
    settings['段评样式'] = newName;
  }
  renderCustomStyles();
  updateHiddenSettings();
  updateStyleSelector();
  renderPreview();
}

// 渲染自定义样式列表
function renderCustomStyles() {
  const container = document.getElementById('customStylesContainer');
  container.innerHTML = '';

  if (Object.keys(customStyles).length === 0) {
    container.innerHTML = '<div class="empty-custom-styles">暂无自定义样式，点击上方"+"添加</div>';
    return;
  }

  Object.keys(customStyles).forEach((name, index) => {
    const styleCard = document.createElement('div');
    styleCard.className = 'custom-style-card';
    // 转义SVG代码中的特殊字符
    const escapedSvg = customStyles[name]
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');

    styleCard.innerHTML = \`
      <div class="custom-style-header">
        <input type="text" class="style-name-input" value="\${name}" data-original="\${name}">
        <div class="style-actions">
          <button class="style-btn preview-btn" title="预览">
            <i class="fas fa-eye"></i>
          </button>
          <button class="style-btn delete-btn" title="删除">
            <i class="fas fa-trash"></i>
          </button>
        </div>
      </div>
      <textarea class="style-code-textarea" rows="4" placeholder="输入SVG代码...">\${escapedSvg}</textarea>
      <div class="style-preview-small">
        <div class="preview-svg-container"></div>
      </div>
    \`;

    // 绑定事件
    const nameInput = styleCard.querySelector('.style-name-input');
    const codeTextarea = styleCard.querySelector('.style-code-textarea');
    const deleteBtn = styleCard.querySelector('.delete-btn');
    const previewBtn = styleCard.querySelector('.preview-btn');

    nameInput.addEventListener('change', () => {
      const newName = nameInput.value.trim();
      const originalName = nameInput.dataset.original;
      if (newName != originalName) {
        renameCustomStyle(originalName, newName);
      }
    });

    codeTextarea.addEventListener('input', () => {
      updateCustomStyle(name, codeTextarea.value);
      // 更新小预览
      updateSmallPreview(styleCard.querySelector('.preview-svg-container'), codeTextarea.value);
    });

    deleteBtn.addEventListener('click', () => deleteCustomStyle(name));

    previewBtn.addEventListener('click', () => {
      // 设置为当前选中样式（使用自定义名称）
      settings['段评样式'] = name;
      document.getElementById('duanpingStyle').value = name;
      updateHiddenSettings();
      renderPreview();
    });

    // 初始化小预览
    updateSmallPreview(styleCard.querySelector('.preview-svg-container'), customStyles[name]);

    container.appendChild(styleCard);
  });
}

// 更新小预览
function updateSmallPreview(container, svgCode) {
  try {
    const preview = svgCode
      .split('$color').join(settings['段评边框颜色'])
      .split('$fontcolor').join(settings['段评字体颜色'])
      .split('$tccolor').join(settings['段评填充颜色'])
      .split('$displayText').join('99+');
    container.innerHTML = preview;
  } catch (e) {
    container.innerHTML = '<span style="color: #999; font-size: 12px;">解析失败</span>';
  }
}

// 渲染预览
function renderPreview() {
  const container = document.getElementById('previewContainer');
  container.innerHTML = '';

  // 添加默认样式
  SVG_TEMPLATES.forEach((svgTemplate, index) => {
    const svgContent = svgTemplate
      .split('$color').join(settings['段评边框颜色'])
      .split('$fontcolor').join(settings['段评字体颜色'])
      .split('$tccolor').join(settings['段评填充颜色'])
      .split('$displayText').join('99+');

    const item = document.createElement('div');
    item.className = \`preview-item \${settings['段评样式'] === String(index) ? 'selected' : ''}\`;
    item.innerHTML = \`
      \${svgContent}
      <div class="preview-label">\${STYLE_NAMES[index]}</div>
    \`;

    item.addEventListener('click', () => {
      settings['段评样式'] = String(index);
      document.getElementById('duanpingStyle').value = String(index);
      updateHiddenSettings();
      renderPreview();
    });

    container.appendChild(item);
  });

  // 添加自定义样式预览
  Object.keys(customStyles).forEach((name) => {
    const svgCode = customStyles[name];
    let svgContent;
    try {
      svgContent = svgCode
        .split('$color').join(settings['段评边框颜色'])
        .split('$fontcolor').join(settings['段评字体颜色'])
        .split('$tccolor').join(settings['段评填充颜色'])
        .split('$displayText').join('99+');
    } catch (e) {
      svgContent = '<svg width="60" height="54" viewBox="0 0 60 54"><text x="30" y="27" text-anchor="middle" fill="#999" font-size="10">解析失败</text></svg>';
    }

    const item = document.createElement('div');
    item.className = \`preview-item \${settings['段评样式'] === name ? 'selected' : ''}\`;
    item.innerHTML = \`
      \${svgContent}
      <div class="preview-label custom-label">\${name}</div>
    \`;

    item.addEventListener('click', () => {
      settings['段评样式'] = name;
      document.getElementById('duanpingStyle').value = name;
      updateHiddenSettings();
      renderPreview();
    });

    container.appendChild(item);
  });
}

// 初始化事件监听
function setupEventListeners() {
  // 段评开关
  document.getElementById('duanpingSwitch').addEventListener('change', (e) => {
    settings['段评开关'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  // 气泡增大开关
  document.getElementById('bubbleLargeSwitch').addEventListener('change', (e) => {
    settings['气泡增大'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  // 段评样式选择
  document.getElementById('duanpingStyle').addEventListener('change', (e) => {
    settings['段评样式'] = e.target.value;
    updateHiddenSettings();
    renderPreview();
  });

  // 边框颜色选择器
  document.getElementById('borderColor').addEventListener('input', (e) => {
    const color = e.target.value;
    settings['段评边框颜色'] = color;
    document.getElementById('borderColorText').value = color;
    updateHiddenSettings();
    renderPreview();
  });

  // 边框颜色文本输入
  document.getElementById('borderColorText').addEventListener('input', (e) => {
    const color = e.target.value;
    if (/^#[0-9A-Fa-f]{6}$/.test(color) || /^#[0-9A-Fa-f]{3}$/.test(color)) {
      settings['段评边框颜色'] = color;
      document.getElementById('borderColor').value = color;
      updateHiddenSettings();
      renderPreview();
    }
  });

  // 字体颜色选择器
  document.getElementById('fontColor').addEventListener('input', (e) => {
