function formatDate(timestamp) {
    const date = new Date(timestamp * 1000);
    return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
}

function isVips(res) {
    const vipEndTime = res.vip_end_time;
    const isVipValue = res.is_vip;

    let vipType;
    if (isVipValue == 0) {
        return '普通用户';
    } else if (isVipValue == 1) {
        vipType = 'VIP';
    } else {
        vipType = 'SVIP';
    }

    if (!vipEndTime || vipEndTime == 0) {
        return `${vipType} (已过期)`;
    }

    const currentTime = Math.floor(Date.now() / 1000);
    const remainingDays = Math.ceil((vipEndTime - currentTime) / (24 * 60 * 60));

    if (currentTime > vipEndTime) {
        return `${vipType} (已过期)`;
    }

    if (remainingDays <= 7) {
        return `${vipType} 剩余${remainingDays}天`;
    }

    if (vipEndTime >= 1912946812) {
        return `${vipType} (永久)`;
    }

    return `${vipType}(${formatDate(vipEndTime)})`;
}

function checkStatus() {
    const token = getToken();
    if (String(token).length < 10) {
        java.longToast('\n🤔请先登陆');
        return;
    }
    java.longToast('\n\n♻️查询中...');

    try {
        const res = JSON.parse(request(`/user_api`, 'POST'));

        if (res.id == undefined) {
            throw new Error(res.msg || '获取用户信息失败');
        }

        result.邮箱 = res.email;

        source.putLoginInfo(JSON.stringify(result));

        let devices = 0;
        try {
            devices = res.device ? Object.keys(JSON.parse(res.device)).length : 0;
        } catch (e) {
            devices = res.device ? 1 : 0;
        }

        const isVip = isVips(res);
        const today = java.timeFormat(new Date()).slice(0, 10);
        const lastReadDate = res.last_read_time ? java.timeFormat(res.last_read_time * 1000).slice(0, 10) : '';
        const todayReadCount = today == lastReadDate ? res.day_read_count : 0;

        const tips = `
${BaseUrl()}
┏┅┅┅┅┅┅┱┄┄┄┄┄┄┄┄┄┄┐
　 🧢昵称 　　　　${(res.nickname || '未设置').padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
　✉️邮箱　　　　${res.email.replace(/(.{3}).*?@/, '$1***@').padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
　🔑密钥　　　　${(`${res.user_key.substring(0, 4)}***${res.user_key.slice(-4)}`).padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
　📅注册时间　　${java.timeFormat(res.register_time * 1000).padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
🗒️今日阅读　　${todayReadCount.toString().padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
📚累计阅读　　${res.all_read_count.toString().padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
🕓最后阅读　　${(res.last_read_time ? java.timeFormat(res.last_read_time * 1000) : '未阅读').padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
📱在线设备　　${devices.toString().padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
　👑会员状态　　${isVip.padEnd(20, '\t')}
┣┅┅┅┅┅┅╉┄┄┄┄┄┄┄┄┄┄┤
　🚫封禁状态　　${res.is_banned ? '已封禁' : '正常　'}　　　　　　　
┗┅┅┅┅┅┅┹┄┄┄┄┄┄┄┄┄┄┘
`;

        java.log(tips);
        java.longToast(tips);

    } catch (e) {
        java.toast(`\n检测登录失败\n${e.message}`);
    }
}

function clearDevice() {
    const token = getToken();
    if (String(token).length < 10) {
        java.longToast('\n🤔请先登陆');
        return;
    }
    let res = request(`/clear`, "POST");
    res = JSON.parse(res);
