function setFindSource() {
	let findSource = result["发现页来源(支持的平台请前往源变量中查看)"];
	if (String(findSource)=="" || String(findSource) == "undefined") {
		findSource = "番茄";
		}
	setVariable("发现页来源",findSource);
 java.longToast(`\n已设置发现页来源为:${findSource}\n设置后请刷新发现页！`)

