function setSearchSource() {
	let searchSource = result["搜索来源(支持的平台请前往源变量中查看,多个来源用英文逗号分割)"];
	if (String(searchSource)=="" || String(searchSource) == "undefined") {
		searchSource = '全部';
		}
	let moreSettings = getVariable("更多设置") || {};
	let tab = moreSettings && moreSettings['搜索模式'] || '小说';
	moreSettings[tab] = searchSource;
	setVariable("更多设置",moreSettings)
  java.longToast(`\n已设置搜索来源为:${tab}-${moreSettings[tab]}\n设置后请重新搜索`)
	}

function saveSettings() {
	  java.longToast(`\n正在保存~`);
    let moreSettings = getVariable("更多设置") || {};
    let body_more = {
        "legado_more":moreSettings
    }
	let data_more = request('/user_settings','POST',body_more)
    const response_more = JSON.parse(data_more);
    let paraSettings = getVariable("段评设置") || {};
    let body_para = {
        "legado_para":paraSettings
    }
	let data_para = request('/user_settings','POST',body_para)
    const response_para = JSON.parse(data_para);
    java.longToast(`\n书源设置:${response_more.msg}\n段评设置:${response_para.msg}`);
	}

    function getSettings() {
    	java.longToast(`\n正在获取~`);
        let more = false;
        let para = false;
        let data_more = request('/user_settings?set_type=legado_more','GET');
        const response_more = JSON.parse(data_more);
        if (response_more.data) {
            setVariable("更多设置",response_more.data)
            more = true;
        }
        let data_para = request('/user_settings?set_type=legado_para','GET');
        const response_para = JSON.parse(data_para);
        if (response_para.data) {
            setVariable("段评设置",response_para.data)
            para=true;
        }
        java.longToast(`\n书源设置:${more?'应用成功':'应用失败'}\n段评设置:${para?'应用成功':'应用失败'}`);
    }

